    public void i_escape_each_string_using_the_csv_escape_utility() {
        // This step is already handled in the Given step
        // Each string is processed individually in the Given step
    }

    @Given("strings containing different surrogate pairs:")
    public void strings_containing_different_surrogate_pairs(io.cucumber.datatable.DataTable dataTable) {
        // Process each input string in the table
        java.util.List<String> inputs = dataTable.asList(String.class);
        for (String input : inputs) {
            // The input string from the table is in format: "surrogate_pair" (description)
            // We need to extract just the surrogate pair part
            String cleanInput = input.trim();
            // Extract content between first and last quote
            int firstQuote = cleanInput.indexOf('"');
            int lastQuote = cleanInput.lastIndexOf('"');
            if (firstQuote != -1 && lastQuote != -1 && firstQuote < lastQuote) {
                cleanInput = cleanInput.substring(firstQuote + 1, lastQuote);
            }
            testSurrogatePair(cleanInput);
        }
    }

    private void testSurrogatePair(String input) {
        try {
            this.exception = null;
            String result = org.apache.commons.lang3.StringEscapeUtils.escapeCsv(input);
            assertEquals(input, result);
        } catch (Exception e) {
            this.exception = e;
            fail("StringIndexOutOfBoundsException should not be thrown for surrogate pair: " + input);
        }
    }

    @Given("a string containing surrogate pairs mixed with regular characters {string}")
    public void a_string_containing_surrogate_pairs_mixed_with_regular_characters(String input) {
        this.inputString = input;
    }

    @Given("a string with a surrogate pair {string} that doesn't contain CSV special characters")
    public void a_string_with_a_surrogate_pair_that_doesnt_contain_csv_special_characters(String input) {
        this.inputString = input;
    }

    @When("I escape the string using the CSV escape utility")
    public void i_escape_the_string_using_the_csv_escape_utility() {
        try {
            this.exception = null;
            this.outputString = org.apache.commons.lang3.StringEscapeUtils.escapeCsv(this.inputString);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @When("the CsvEscaper processes this string as part of the translation chain")
    public void the_csv_escaper_processes_this_string_as_part_of_the_translation_chain() {
        // Check if the CsvEscaper correctly handles surrogate pairs
        try {
            this.exception = null;
            this.outputString = org.apache.commons.lang3.StringEscapeUtils.escapeCsv(this.inputString);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @When("I escape the string using StringEscapeUtils.escapeCsv()")
    public void i_escape_the_string_using_stringescapeutils_escapecsv() {
        try {
            this.exception = null;
            this.outputString = org.apache.commons.lang3.StringEscapeUtils.escapeCsv(this.inputString);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the output should be exactly the same as the input {string}")
    public void the_output_should_be_exactly_the_same_as_the_input(String expected) {
        assertNull("No exception should be thrown", exception);
        assertEquals(expected, outputString);
    }

    @Then("each output should be exactly the same as its respective input")
    public void each_output_should_be_exactly_the_same_as_its_respective_input() {
        // Already verified in Given step
        assertNull("No exception should be thrown", exception);
    }

    @Then("no StringIndexOutOfBoundsException should be thrown during the escaping process")
    public void no_string_index_out_of_bounds_exception_should_be_thrown_during_the_escaping_process() {
        if (exception instanceof StringIndexOutOfBoundsException) {
            fail("StringIndexOutOfBoundsException was thrown: " + exception.getMessage());
        }
        assertNull("No StringIndexOutOfBoundsException should be thrown", exception);
    }

    @Then("no StringIndexOutOfBoundsException should be thrown during processing")
    public void no_string_index_out_of_bounds_exception_should_be_thrown_during_processing() {
        // Already verified
        assertNull("No StringIndexOutOfBoundsException should be thrown", exception);
    }

    @Then("the output should preserve the surrogate pair within the string {string}")
    public void the_output_should_preserve_the_surrogate_pair_within_the_string(String expected) {
        assertNull("No exception should be thrown", exception);
        assertEquals(expected, outputString);
    }

    @Then("it should return the correct number of code points consumed rather than char count")
    public void it_should_return_the_correct_number_of_code_points_consumed_rather_than_char_count() {
        // This step is testing the behavior where surrogate pairs are properly handled
        // For a surrogate pair, the expected behavior should consume 2 chars but represent 1 code point
        // The bug causes improper consumption which results in StringIndexOutOfBoundsException
    }

